function Update-GodModeDeityManifest { param([string]$Project='.',[array]$ActiveMissions=@(),[array]$Events=@()) $r=Initialize-GodModeStructure $Project; $entities=@(); foreach($e in Get-GodModeBaseEntityCatalog){ $ent=@{schema_version=1;id=('entity-'+$e.role.ToLowerInvariant());role=$e.role;name=$e.name;form=$e.form;tier='seed';level=1;xp=0;stability=72;state='active';accent=$e.accent;browser_status='not_proven';windows_route_status='probed_or_pending';metabolic_rate='unknown';latest_event='MVP profile generated from deterministic catalog';dna_seed=[Math]::Abs($e.role.GetHashCode()).ToString()}; $entities+=$ent; Write-GodModeJsonAtomic (Join-GodModePath $r ("profiles/regular/$($e.role).json")) $ent|Out-Null }; $m=@{schema_version=1;updated_at=Get-GodModeIso;title='AEONTHRA Codex God Creature Ascension Engine';mode='css3d-mvp';entities=$entities;active_missions=$ActiveMissions;events=$Events;degraded_reasons=@('threejs_deferred_css3d_mvp');proof_note='Visual state derives from local JSON projections only.'}; Write-GodModeJsonAtomic (Join-GodModePath $r 'arena/deity-manifest.json') $m|Out-Null; $m }
